class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        if not self.intervals:
            self.intervals.append([value, value])
        else:
            for i, interval in enumerate(self.intervals):
                if value < interval[0]:
                    self.intervals.insert(i, [value, value])
                    break
                elif value <= interval[1]:
                    interval[1] = value
                    break
                elif i == len(self.intervals) - 1:
                    if value == interval[1] + 1:
                        interval[1] = value
                    else:
                        self.intervals.append([value, value])
                    break
                elif value == interval[1] + 1:
                    interval[1] = value
                    if i + 1 < len(self.intervals) and value + 1 == self.intervals[i + 1][0]:
                        interval[1] = self.intervals[i + 1][1]
                        del self.intervals[i + 1]
                    break

    def getIntervals(self) -> List[List[int]]:
        return self.intervals
